LAYER
	NAME "puerta"
	GROUP "MPU"
	TYPE point
	PROCESSING "LABEL_NO_CLIP=1"
	#HEADER "plantillas/inicio.html"
	#TEMPLATE "plantillas/mpu/mpu/puerta.html"
	#FOOTER "plantillas/fin.html"
	STATUS on
	VALIDATION
		"tipo" "[A-Z]{1}$"
		"default_tipo" "P,S,G"
	END
	DATA "geom FROM (SELECT gid, codi_puert, id_puerta, esta_puert, id_lote, id_mzna, tipo, geom FROM geo.tg_puerta) as mpu using unique gid using srid=32718"
	FILTER ("[tipo]" IN "%tipo%")
	INCLUDE "configuracion/postgresql_mpu.map"
	PROJECTION
		"init=epsg:32718"
	END
	CLASSITEM "tipo"
	METADATA
		"wms_group_title" "MPU"
		"queryable" "true"
		"wms_metadataurl_href" ""
		"wms_metadataurl_format" "text/xml"
		"wms_metadataurl_type" "TC211"
		"wms_title" "Puerta"
		"wms_abstract" "Puerta || Municipalidad Provincial de Urubamba - Cusco :: Perú"
		"wms_credit" "MPU"
		"wms_dataurl" ""
		"wms_dataurl_format" "text/html"
		"wms_dataurl_href" ""
		"wms_extent" "807683.9653000003 8526364.0129 814882.6846000003 8531884.0174"
		"wms_srs" "EPSG:32718"
		"wms_include_items" "all"
		"wms_exclude_items" "gid"
	END
	CLASS
		NAME "P"
		EXPRESSION "P"
		STYLE
			SYMBOL "cuadrado"
			SIZE 4
			COLOR 0 255 255
			OUTLINECOLOR 0 0 0
		END
	END
	CLASS
		NAME "S"
		EXPRESSION "S"
		STYLE
			SYMBOL "cuadrado"
			SIZE 4
			COLOR 255 255 0
			OUTLINECOLOR 0 0 0
		END
	END
	CLASS
		NAME "G"
		EXPRESSION "G"
		STYLE
			SYMBOL "cuadrado"
			SIZE 4
			COLOR 255 0 255
			OUTLINECOLOR 0 0 0
		END
	END
END # Layer